const today = new Date().toLocaleDateString('en-GB');
const inboxRows = $input.all();
if (inboxRows.some(i => i.json && i.json.error)) throw new Error('Unable to read the AI Inbox from Notion');
const valueOf = (obj, names) => { for (const name of names) { const value = obj[name]; if (value !== undefined && value !== null && value !== '') return value; } return ''; };
const toText = (value) => { if (value === undefined || value === null) return ''; if (Array.isArray(value)) return value.map(toText).filter(Boolean).join(', '); if (typeof value === 'object') return value.name || value.value || value.plain_text || (value.text && value.text.content) || ''; return value.toString(); };
const toTags = (value) => { if (!value) return []; const tags = Array.isArray(value) ? value : [value]; return tags.map(toText).filter(Boolean); };
const items = [];
for (const input of inboxRows) {
  const j = input.json;
  const p = j.properties || {};
  const data = { ...p, ...j };
  const status = toText(valueOf(data, ['property_status', 'Status', 'status']));
  if (status && status !== 'Inbox') continue;
  const title = toText(valueOf(data, ['property_name', 'name', 'Name', 'Title', 'title']));
  const summary = toText(valueOf(data, ['property_summary', 'summary', 'Summary']));
  const source = toText(valueOf(data, ['property_source', 'source', 'Source']));
  const url = toText(valueOf(data, ['property_url', 'url', 'URL']));
  const tags = toTags(valueOf(data, ['property_tags', 'tags', 'Tags']));
  if (!title && !summary) continue;
  items.push({ id: j.id, title, source, summary, tags, url });
}
return [{ json: { date: today, items: items.slice(0, 20), count: items.length } }];

const incoming = $input.first()?.json || {};
if (Array.isArray(incoming.blocks) && incoming.blocks.length) return $input.all();

const prepared = $('Prepare').first().json || {};
const items = Array.isArray(prepared.items) ? prepared.items : [];
const date = prepared.date || new Date().toLocaleDateString('en-GB');
const capUtf16 = (value, limit = 1900) => {
  const string = (value ?? '').toString();
  let units = 0;
  let result = '';
  for (const character of string) {
    const size = character.codePointAt(0) > 0xffff ? 2 : 1;
    if (units + size > limit) break;
    result += character;
    units += size;
  }
  return result;
};
const richText = (content) => [{ type: 'text', text: { content: capUtf16(content || '') } }];
const block = (type, content) => ({ object: 'block', type, [type]: { rich_text: richText(content) } });
const divider = () => ({ object: 'block', type: 'divider', divider: {} });
const blocks = [
  block('heading_2', `Daily Brief - ${date}`),
  block('paragraph', 'Local fallback: the bridge returned no blocks, so this brief only includes the available Notion captures.'),
  block('heading_3', "Today's inbox"),
];

if (!items.length) {
  blocks.push(block('paragraph', 'Nothing to report.'));
} else {
  for (const item of items) {
    const title = item.title || '(untitled)';
    const summary = item.summary || 'No summary available.';
    const source = item.source ? ` · Source: ${item.source}` : '';
    const tags = Array.isArray(item.tags) && item.tags.length ? ` · Tags: ${item.tags.join(', ')}` : '';
    blocks.push(block('bulleted_list_item', `${title} - ${summary}${source}${tags}`));
  }
}

blocks.push(
  block('heading_3', "Today's action"),
  block('paragraph', items.length
    ? 'Review the captures above and choose the one that best supports the active objectives.'
    : 'No captures to process.'),
  divider(),
);
return [{ json: { ok: true, fallback: true, brief: `Local fallback - ${date}`, blocks, count: items.length } }];

const STALE_DAYS = 7;
const COMPLETED_LOOKBACK_DAYS = 3;
const now = new Date();
const sourceNodes = ['Notes - blocks', 'System context - blocks', 'Active objectives', 'Tasks - all'];

for (const name of sourceNodes) {
  if ($(name).all().some(item => item.json && item.json.error)) {
    throw new Error('Notion read failed: ' + name);
  }
}

const getText = (block) => {
  if (typeof block.content === 'string') return block.content;
  const content = block[block.type];
  if (!content) return '';
  return (content.rich_text || []).map(text => text.plain_text || '').join('');
};
const isChecked = (block) => (
  block.checked !== undefined ? block.checked : ((block.to_do || {}).checked || false)
);

const noteBlocks = $('Notes - blocks').all().map(item => item.json).filter(block => block && block.type);
let section = null;
const today = [];
const journal = [];
const todos = [];
let journalDate = null;
for (const block of noteBlocks) {
  const text = getText(block);
  const type = block.type;
  if (type === 'heading_2' || type === 'heading_1') {
    if (text.includes('Today')) section = 'today';
    else if (text.includes('Journal')) section = 'journal';
    else if (text.includes('Todo') || text.includes('✅')) section = 'todos';
    else if (text.includes('Archive') || text.includes('🗄')) break;
    else section = null;
    continue;
  }
  if (type === 'heading_3' && section === 'journal') {
    if (journalDate !== null) break;
    journalDate = text;
    continue;
  }
  if (!text) continue;
  if (section === 'today') today.push(text);
  else if (section === 'journal' && journalDate !== null) journal.push(text);
  else if (section === 'todos') todos.push((isChecked(block) ? '✓' : '☐') + ' ' + text);
}

const contextParts = [];
if (today.length) contextParts.push("Today's notes:\n" + today.map(line => '- ' + line).join('\n'));
if (journalDate && journal.length) {
  contextParts.push('Journal (' + journalDate + '):\n' + journal.map(line => '- ' + line).join('\n'));
}
if (todos.length) contextParts.push('Open todos:\n' + todos.join('\n'));
const context = contextParts.join('\n\n').slice(0, 3000);

const systemLines = [];
for (const block of $('System context - blocks').all().map(item => item.json).filter(block => block && block.type)) {
  const text = getText(block).trim();
  if (!text) continue;
  systemLines.push(block.type.startsWith('heading_') ? '## ' + text : '- ' + text);
}
const system_context = systemLines.join('\n').slice(0, 12000);

const normalize = (value) => value.toString().toLowerCase().normalize('NFD')
  .replace(/[̀-ͯ]/g, '').replace(/[^a-z0-9]+/g, '');
const toText = (value) => {
  if (value === undefined || value === null) return '';
  if (Array.isArray(value)) return value.map(toText).filter(Boolean).join(', ');
  if (typeof value === 'object') {
    return value.name || value.value || value.plain_text || value.start ||
      (value.text && value.text.content) || '';
  }
  return value.toString();
};
const mapProperties = (json) => {
  const mapped = {};
  const source = { ...(json.properties || {}), ...json };
  for (const key of Object.keys(source)) {
    mapped[normalize(key.startsWith('property_') ? key.slice(9) : key)] = source[key];
  }
  return mapped;
};
const field = (mapped, names) => {
  for (const name of names) {
    const value = toText(mapped[name]);
    if (value) return value;
  }
  return '';
};

const objectives = [];
for (const item of $('Active objectives').all()) {
  const mapped = mapProperties(item.json || {});
  const name = field(mapped, ['name']);
  if (!name) continue;
  const status = field(mapped, ['status']);
  if (status && status !== 'Active') continue;
  objectives.push({
    name,
    area: field(mapped, ['area']),
    priority: field(mapped, ['priority']),
    current_state: field(mapped, ['currentstate']),
    next_step: field(mapped, ['nextstep']),
    horizon: field(mapped, ['horizon']),
  });
}

const open_tasks = [];
const completed_tasks = [];
for (const item of $('Tasks - all').all()) {
  const mapped = mapProperties(item.json || {});
  const title = field(mapped, ['task']);
  if (!title) continue;
  const status = field(mapped, ['status']);
  const common = {
    title,
    area: field(mapped, ['area']),
    why: field(mapped, ['why']),
    feedback: field(mapped, ['feedback']),
  };
  if (status === 'To do' || !status) {
    const proposedOn = field(mapped, ['proposedon']);
    if (proposedOn) {
      const age = (now - new Date(proposedOn)) / 86400000;
      if (age > STALE_DAYS) continue;
    }
    open_tasks.push({ ...common, proposed_on: proposedOn });
  } else if (status === 'Done') {
    const completedOn = field(mapped, ['doneon', 'lasteditedtime']);
    if (!completedOn) continue;
    const age = (now - new Date(completedOn)) / 86400000;
    if (!Number.isFinite(age) || age < 0 || age > COMPLETED_LOOKBACK_DAYS) continue;
    completed_tasks.push({ ...common, completed_on: completedOn });
  }
}
completed_tasks.sort((a, b) => new Date(b.completed_on) - new Date(a.completed_on));

const prepared = $('Prepare').first().json || {};
return [{
  json: {
    ...prepared,
    context,
    system_context,
    objectives,
    open_tasks,
    completed_tasks: completed_tasks.slice(0, 10),
  },
}];

const output = $('Brief fallback if Claude fails').first().json || {};
const tasks = Array.isArray(output.tasks) ? output.tasks : [];
const openTasks = (($('Enrich payload').first().json || {}).open_tasks) || [];
const normalize = (value) => (value || '').toString().toLowerCase().normalize('NFD')
  .replace(/[̀-ͯ]/g, '').replace(/[^a-z0-9]+/g, '');
const blocked = new Set(openTasks.map(task => normalize(task.title)));
const seen = new Set();
const result = [];

for (const task of tasks) {
  if (!task || !task.title) continue;
  const key = normalize(task.title);
  if (!key || blocked.has(key) || seen.has(key)) continue;
  seen.add(key);
  result.push({
    json: {
      title: task.title,
      area: task.area || 'Knowledge',
      why: task.why || '',
    },
  });
}
return result;

const fb = $('Brief fallback if Claude fails').first().json || {};
const blocks = Array.isArray(fb.blocks) ? fb.blocks : [];
const firstBlocks = $('Brief: first block').all().map(i => i.json).filter(b => b && b.id);
const after = firstBlocks.length ? firstBlocks[0].id : null;
const children = [{ object: 'block', type: 'divider', divider: {} }].concat(blocks);
const body = after ? { children, after } : { children };
return [{ json: { body } }];

const STALE_DAYS = 7;
const now = new Date();
const normalize = (value) => value.toString().toLowerCase().normalize('NFD')
  .replace(/[̀-ͯ]/g, '').replace(/[^a-z0-9]+/g, '');
const toText = (value) => {
  if (value === undefined || value === null) return '';
  if (Array.isArray(value)) return value.map(toText).filter(Boolean).join(', ');
  if (typeof value === 'object') {
    return value.name || value.value || value.plain_text || value.start ||
      (value.text && value.text.content) || '';
  }
  return value.toString();
};
const mapProperties = (json) => {
  const mapped = {};
  const source = { ...(json.properties || {}), ...json };
  for (const key of Object.keys(source)) {
    mapped[normalize(key.startsWith('property_') ? key.slice(9) : key)] = source[key];
  }
  return mapped;
};
const result = [];

for (const item of $('Tasks - all').all()) {
  const json = item.json || {};
  if (!json.id) continue;
  const mapped = mapProperties(json);
  if (toText(mapped.status) !== 'To do') continue;
  const proposedOn = toText(mapped.proposedon);
  if (!proposedOn) continue;
  const age = (now - new Date(proposedOn)) / 86400000;
  if (age > STALE_DAYS) result.push({ json: { id: json.id } });
}
return result;

const fallback = $('Brief fallback if Claude fails').first().json || {};
const engine = fallback.engine || (fallback.fallback ? 'none' : 'claude');
const context_source = fallback.context_source || 'fallback';
if (engine === 'claude' && context_source === 'notion') return [];
const date = $('Prepare').first().json.date || new Date().toLocaleDateString('en-GB');
return [{ json: { engine, context_source, date } }];
